@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@attribute [Microsoft.AspNetCore.Components.ExcludeFromInteractiveRoutingAttribute]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application collects minimal data necessary to provide its services.
    We use cookies to remember your preferences and improve your experience.
</p>

<h2>Cookie Usage</h2>

<p>
    We use a consent cookie to track whether you have acknowledged our cookie policy.
</p>

@if (HasConsented)
{
    <div class="alert alert-success">
        ✓ You have already accepted cookies.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted cookies.
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext.Request.Cookies.ContainsKey("consent");
    }
}

